arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(CustomerData.Churned),
        featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(CustomerData.Churned));
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromOptions(new Microsoft.Extensions.ML.PredictionEnginePoolOptions<CustomerData, ChurnPrediction>
    {
        ModelLoader = new InMemoryModelLoader(model, mlContext),
    });

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API is running.");

app.MapPost("/predict", (CustomerInput input,
    Microsoft.Extensions.ML.PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var data = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory,
    };
    var prediction = pool.Predict(data);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
    });
});

app.Run();

// --- Models ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")]
    public bool Churned { get; set; }
}

public class CustomerInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = "";
    public float PurchaseHistory { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

// Loads a pre-trained model from memory into the PredictionEnginePool
public sealed class InMemoryModelLoader : Microsoft.Extensions.ML.ModelLoader
{
    private readonly ITransformer _model;
    private readonly MLContext _mlContext;

    public InMemoryModelLoader(ITransformer model, MLContext mlContext)
    {
        _model = model;
        _mlContext = mlContext;
    }

    public override ITransformer GetModel() => _model;
    public override ITransformer GetModelReloadToken() => _model;
}

