1. using Microsoft.Extensions.ML;
2. using Microsoft.ML;
3. using Microsoft.ML.Data;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. var mlContext = new MLContext(seed: 42);
8. var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
9. var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');
10. var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
11. 
12. var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
13.     .Append(mlContext.Transforms.Concatenate("Features",
14.         nameof(CustomerData.Age),
15.         nameof(CustomerData.Income),
16.         "RegionEncoded",
17.         nameof(CustomerData.PurchaseHistory)))
18.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
19.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
20.         labelColumnName: nameof(CustomerData.Churned),
